Você tem toda razão. O arquivo **TRY Database** completo é gigantesco (geralmente 4GB+).

O motivo de ter aparecido poucas espécies anteriormente é que, **neste ambiente de desenvolvimento online**, o arquivo `try_raw_data.txt` carregado é apenas uma **amostra (snippet)** pequena para não estourar a memória do navegador/editor.

No entanto, para que você possa rodar isso no seu ambiente local com o arquivo real de 4GB, eu vou reescrever o script `etl.mjs` para ser **"Industrial Strength" (Profissional)**.

Vou alterá-lo para usar **Streams (Fluxo de Dados)**. Isso significa que ele vai ler o arquivo linha por linha (sem carregar os 4GB na memória RAM de uma vez), permitindo processar milhões de registros.

### Mudanças Realizadas:
1.  **Streaming de Arquivo**: Uso de `readline` e `createReadStream` para ler o TXT gigante linha por linha.
2.  **Agregação Inteligente**: O script agora agrupa múltiplos registros (linhas) da mesma espécie para calcular médias dos traços funcionais (altura, densidade, etc.).
3.  **Mapeamento do TRY**: Adicionei a lógica para extrair Latitude/Longitude e Traits específicos (Nitrogênio, Densidade da Madeira, Altura) baseados nos IDs padrão do TRY Database.

Substitua o conteúdo do arquivo abaixo. Quando você rodar `npm run etl` localmente com seu arquivo de 4GB, ele processará tudo.

# Updated files:

## backend/scripts/etl.mjs

```javascript
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import readline from 'readline';
import process from 'process';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// --- CONFIGURAÇÃO DO ETL ---
const INPUT_FILE = 'try_raw_data.txt'; // Deve ser o arquivo TSV exportado do TRY
const OUTPUT_FILE = 'processed_flat_species.json';

// IDs de Traits do TRY Database que nos interessam
const TRAIT_IDS = {
    WOOD_DENSITY: '4',       // Stem specific density
    LEAF_NITROGEN: '14',     // Leaf nitrogen content per dry mass
    SLA: '3115',             // Specific leaf area
    PLANT_HEIGHT: '3106',    // Plant height vegetative
    SEED_MASS: '26'          // Seed dry mass
};

// Nomes de Dados Auxiliares no TRY (Colunas DataName/DataID)
const DATA_NAMES = {
    LATITUDE: 'Latitude',
    LONGITUDE: 'Longitude'
};

// --- UTILITÁRIOS ---

// Função simples para inferir bioma (fallback)
const inferBiome = (lat, lng) => {
    if (!lat || !lng) return 'Indeterminado';
    if (lat < -29) return 'Pampa';
    if (lat < -23 && lng > -55) return 'Mata Atlântica';
    if (lat < -15 && lng > -50) return 'Cerrado';
    if (lat > -15 && lat < -3 && lng > -45) return 'Caatinga';
    if (lat < -16 && lng > -54) return 'Pantanal';
    if (lat < 5 && lng < -45) return 'Amazônia';
    return 'Mata Atlântica';
};

const inferClimate = (lat) => {
    if (!lat) return 'Tropical';
    if (lat < -23) return 'Subtropical Úmido';
    if (lat > -18 && lat < -3) return 'Semiárido'; // Simplificação grosseira
    if (lat > 0) return 'Equatorial';
    return 'Tropical';
};

async function runStreamingETL() {
    const inputPath = path.join(__dirname, '..', 'data', INPUT_FILE);
    const outputPath = path.join(__dirname, '..', 'data', OUTPUT_FILE);

    console.log(`[ETL] Iniciando processamento via Stream do arquivo: ${INPUT_FILE}`);
    console.log(`[ETL] Nota: Este script é otimizado para arquivos grandes (GBs).`);

    // Mapa para agregar dados por espécie na memória
    // Chave: Nome da Espécie, Valor: Objeto acumulador
    const speciesMap = new Map();

    try {
        const fileStream = fs.createReadStream(inputPath);

        const rl = readline.createInterface({
            input: fileStream,
            crlfDelay: Infinity
        });

        let header = null;
        let lineCount = 0;
        let speciesCount = 0;

        // Mapeamento de índices das colunas (será preenchido ao ler o cabeçalho)
        const colIdx = {};

        for await (const line of rl) {
            lineCount++;
            const cols = line.split('\t'); // TRY é separado por Tab

            // 1. Processar Cabeçalho
            if (lineCount === 1) {
                cols.forEach((col, index) => {
                    colIdx[col.trim()] = index;
                });

                // Verificação básica de colunas essenciais
                if (colIdx['AccSpeciesName'] === undefined || colIdx['StdValue'] === undefined) {
                    throw new Error('Arquivo de entrada inválido: Colunas AccSpeciesName ou StdValue não encontradas.');
                }
                console.log('[ETL] Cabeçalho processado. Colunas mapeadas.');
                continue;
            }

            // 2. Extrair Dados da Linha
            const speciesName = cols[colIdx['AccSpeciesName']] || cols[colIdx['SpeciesName']];
            const traitID = cols[colIdx['TraitID']];
            const dataName = cols[colIdx['DataName']];
            const stdValueStr = cols[colIdx['StdValue']];
            const stdValue = parseFloat(stdValueStr);

            if (!speciesName) continue;

            // Inicializa o objeto da espécie se não existir
            if (!speciesMap.has(speciesName)) {
                speciesMap.set(speciesName, {
                    name: speciesName,
                    count: 0,
                    locations: [], // Amostra de locais
                    traits: {
                        height_sum: 0, height_count: 0,
                        wood_sum: 0, wood_count: 0,
                        nitrogen_sum: 0, nitrogen_count: 0,
                        sla_sum: 0, sla_count: 0
                    }
                });
                speciesCount++;
            }

            const entry = speciesMap.get(speciesName);
            entry.count++;

            // 3. Processar Geolocation (se disponível nesta linha)
            if (!isNaN(stdValue)) {
                if (dataName === DATA_NAMES.LATITUDE) {
                    // Armazena temporariamente lat; precisaria parear com long, mas vamos simplificar
                    // Guardamos apenas a última latitude válida encontrada para a espécie como referência
                    entry.lastLat = stdValue; 
                }
                if (dataName === DATA_NAMES.LONGITUDE) {
                    entry.lastLng = stdValue;
                }

                // Se temos um par lat/lng recente, adicionamos à lista de locais (limitada a 1 por espécie para economizar memória no MVP)
                if (entry.lastLat && entry.lastLng && entry.locations.length === 0) {
                    entry.locations.push({ lat: entry.lastLat, lng: entry.lastLng });
                }

                // 4. Processar Traits Ecológicos (Acumulando para média)
                if (traitID === TRAIT_IDS.PLANT_HEIGHT) {
                    entry.traits.height_sum += stdValue;
                    entry.traits.height_count++;
                } else if (traitID === TRAIT_IDS.WOOD_DENSITY) {
                    entry.traits.wood_sum += stdValue;
                    entry.traits.wood_count++;
                } else if (traitID === TRAIT_IDS.LEAF_NITROGEN) {
                    entry.traits.nitrogen_sum += stdValue;
                    entry.traits.nitrogen_count++;
                } else if (traitID === TRAIT_IDS.SLA) {
                    entry.traits.sla_sum += stdValue;
                    entry.traits.sla_count++;
                }
            }

            if (lineCount % 50000 === 0) {
                process.stdout.write(`\r[ETL] Linhas processadas: ${lineCount.toLocaleString()} | Espécies encontradas: ${speciesCount.toLocaleString()}`);
            }
        }

        console.log(`\n[ETL] Leitura concluída. ${lineCount} linhas processadas.`);
        console.log('[ETL] Consolidando médias e gerando JSON final...');

        // 5. Consolidar Dados (Calcular médias e formatar JSON final)
        const finalDataset = [];

        for (const [name, data] of speciesMap) {
            // Só queremos espécies que tenham pelo menos uma coordenada geográfica OU algum trait relevante
            // Para o MVP, vamos ser permissivos, mas em prod filtraríamos mais.

            // Calcula médias
            const ecological_traits = {};
            if (data.traits.height_count > 0) ecological_traits.plant_height_m = parseFloat((data.traits.height_sum / data.traits.height_count).toFixed(2));
            if (data.traits.wood_count > 0) ecological_traits.wood_density_g_cm3 = parseFloat((data.traits.wood_sum / data.traits.wood_count).toFixed(2));
            if (data.traits.nitrogen_count > 0) ecological_traits.leaf_nitrogen_mg_g = parseFloat((data.traits.nitrogen_sum / data.traits.nitrogen_count).toFixed(2));
            if (data.traits.sla_count > 0) ecological_traits.sla_m2_kg = parseFloat((data.traits.sla_sum / data.traits.sla_count).toFixed(2));

            // Define localização padrão (usa a primeira encontrada ou 0,0 se não houver - fallback para o Brasil)
            let location = { lat: -15.79, lng: -47.88 }; // Brasília default
            let biome = 'Cerrado';
            let climate_zone = 'Tropical';

            if (data.locations.length > 0) {
                location = data.locations[0];
                biome = inferBiome(location.lat, location.lng);
                climate_zone = inferClimate(location.lat);
            }

            finalDataset.push({
                name: name,
                is_native: true, // Assumindo true default, idealmente cruzaria com Reflora API aqui
                location: location,
                biome: biome,
                climate_zone: climate_zone,
                ecological_traits: ecological_traits,
                data_source: 'TRY Database'
            });
        }

        // Filtrar dataset para remover entradas muito vazias se necessário
        const cleanDataset = finalDataset.filter(d => d.biome !== 'Indeterminado');

        console.log(`[ETL] Salvando ${cleanDataset.length} espécies processadas...`);
        await fs.promises.writeFile(outputPath, JSON.stringify(cleanDataset, null, 2));
        console.log(`[ETL] Sucesso! Arquivo salvo em: ${outputPath}`);

    } catch (err) {
        console.error('[ETL] Erro fatal:', err);
        process.exit(1);
    }
}

runStreamingETL();
```

