export async function getAgroforestryPlan(request: PlanRequest, language: 'pt' | 'en'): Promise<PlanResponse> {
  console.log(`Calling Gemini API for language: ${language}`, request);

  const { systemInstruction, userPromptTemplate, preferredSpeciesTextTemplate, dataSourceTextTemplate, wfoSpeciesTextTemplate } = prompts[language].planner;
  const objectivesText = request.objectives.join(', ');

  let preferredSpeciesText = '';
  if (request.preferred_species && request.preferred_species.length > 0) {
    const speciesList = request.preferred_species.join(', ');
    preferredSpeciesText = preferredSpeciesTextTemplate.replace('{speciesList}', speciesList);
  }

  let dataSourceText = '';
  if (request.data_source_link) {
      dataSourceText = dataSourceTextTemplate.replace('{dataSourceLink}', request.data_source_link);
  }

  let wfoSpeciesText = '';
  if (request.wfo_species && request.wfo_species.length > 0) {
      // PROMPT ENGINEERING AVANÇADO (Reflora + Traits):
      // Monta uma "Ficha Técnica" para a IA raciocinar
      const speciesList = request.wfo_species
        .map(s => {
            // Header: Nome e Família
            let details = `> **${s.name}**`;
            if (s.family) details += ` (${s.family})`;

            const meta = [];

            // Dados da Reflora
            if (s.is_native !== undefined) meta.push(s.is_native ? 'Nativa do Brasil' : 'Exótica');
            if (s.biomes && s.biomes.length > 0) meta.push(`Biomas: ${s.biomes.join(', ')}`);
            if (s.life_form && s.life_form.length > 0) meta.push(`Forma: ${s.life_form.join(', ')}`);
            if (s.conservation_status) meta.push(`Status: ${s.conservation_status}`);

            // Dados Funcionais (TRY)
            if (s.ecological_traits) {
                const t = s.ecological_traits;
                if (t.plant_height_m) meta.push(`Alt. Máx: ${t.plant_height_m}m`);
                if (t.wood_density_g_cm3) meta.push(`Dens. Madeira: ${t.wood_density_g_cm3}g/cm³`);
                if (t.leaf_nitrogen_mg_g) meta.push(`N Foliar: ${t.leaf_nitrogen_mg_g}mg/g`);
                if (t.sla_m2_kg) meta.push(`SLA: ${t.sla_m2_kg}m²/kg`);
            }

            if (meta.length > 0) {
                details += `\n  - Dados: ${meta.join(' | ')}`;
            }
            return details;
        })
        .join('\n');

      wfoSpeciesText = wfoSpeciesTextTemplate.replace('{wfoSpeciesList}', speciesList);
  }

  const userPrompt = userPromptTemplate
    .replace('{area_ha}', request.area_ha.toFixed(3))
    .replace('{soil_type}', request.soil_type)
    .replace('{climate}', request.climate)
    .replace('{objectivesText}', objectivesText)
    .replace('{preferredSpeciesText}', preferredSpeciesText)
    .replace('{dataSourceText}', dataSourceText)
    .replace('{wfoSpeciesText}', wfoSpeciesText);


  try {
    const response = await ai.models.generateContent({
        model: "gemini-2.5-pro",
        contents: userPrompt,
        config: {
            systemInstruction: systemInstruction,
            responseMimeType: "application/json",
            responseSchema: planResponseSchema,
            temperature: 0.7,
        },
    });

    const planJson = response.text.trim();
    const plan = JSON.parse(planJson) as PlanResponse;

    // --- Post-process to arrange species in strategic rows ---
    plan.consortium_pattern = [...plan.map_layers];

    const polygonCoords = request.area_geojson.geometry.coordinates[0];

    function getBounds(coords: number[][]) {
        let minLat = 90, maxLat = -90, minLng = 180, maxLng = -180;
        coords.forEach(([lng, lat]) => {
            minLat = Math.min(minLat, lat);
            maxLat = Math.max(maxLat, lat);
            minLng = Math.min(minLng, lng);
            maxLng = Math.max(maxLng, lng);
        });
        return { minLat, maxLat, minLng, maxLng };
    }

    function isPointInPolygon(point: [number, number], polygon: number[][]): boolean {
        const [x, y] = point;
        let isInside = false;
        for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
            const [xi, yi] = polygon[i];
            const [xj, yj] = polygon[j];

            const intersect = ((yi > y) !== (yj > y))
                && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
            if (intersect) isInside = !isInside;
        }
        return isInside;
    }

    const { minLat, maxLat, minLng, maxLng } = getBounds(polygonCoords);
    const centerLat = minLat + (maxLat - minLat) / 2;

    const ROW_SPACING_METERS = 5; 
    const PLANT_SPACING_METERS = 2;

    const metersToLatDeg = (m: number) => m / 111132;
    const metersToLngDeg = (m: number, lat: number) => m / (111320 * Math.cos(lat * Math.PI / 180));

    const latStep = metersToLatDeg(PLANT_SPACING_METERS);
    const lngStep = metersToLngDeg(ROW_SPACING_METERS, centerLat);

    const allPlantingSpots: [number, number][] = [];

    for (let lng = minLng; lng <= maxLng; lng += lngStep) {
        for (let lat = minLat; lat <= maxLat; lat += latStep) {
            if (isPointInPolygon([lng, lat], polygonCoords)) {
                allPlantingSpots.push([lat, lng]);
            }
        }
    }

    const speciesConsortiumPattern = plan.consortium_pattern;

    if (speciesConsortiumPattern.length === 0 || allPlantingSpots.length === 0) {
        plan.map_layers = [];
        return plan;
    }

    const fullPlantingList: SpeciesPlacement[] = allPlantingSpots.map((spot, index) => {
        const speciesTemplate = speciesConsortiumPattern[index % speciesConsortiumPattern.length];
        return {
            species: speciesTemplate.species,
            strata: speciesTemplate.strata,
            info: speciesTemplate.info,
            coordinates: spot,
            spacing_meters: speciesTemplate.spacing_meters,
        };
    });

    plan.map_layers = fullPlantingList;

    return plan;

  } catch (error) {
      console.error("Error calling Gemini API:", error);
      throw new Error("Failed to generate a plan from the AI. The model may have returned an invalid response. Please try again.");
  }
};

